import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"Instalando Mods","description":"Um guia passo a passo de como instalar mods para Fabric.","frontmatter":{"title":"Instalando Mods","description":"Um guia passo a passo de como instalar mods para Fabric.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"pt_br/players/installing-mods.md","filePath":"translated/pt_br/players/installing-mods.md","lastUpdated":1772272927000}`);var s={name:`pt_br/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalando Mods <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalando Mods”">​</a></h1><p>Este guia o orientará na instalação de mods para Fabric usando o Minecraft Launcher.</p><p>Para launchers de terceiros, você deve consultar suas devidas documentações.</p><h2 id="_1-baixar-o-mod" tabindex="-1">1. Baixar o Mod <a class="header-anchor" href="#_1-baixar-o-mod" aria-label="Permalink to “1. Baixar o Mod”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Você deve baixar mods apenas de fontes que confia. Para mais informações sobre como encontrar mods, veja o guia <a href="./finding-mods">Encontrando Mods Confiáveis</a>.</p></div><p>A maioria dos mods requer Fabric API, o qual pode ser instalado por meio do <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> ou <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>Ao instalar mods, certifique-se de que:</p><ul><li>Eles funcionam na versão do Minecraft você quer jogar. Por exemplo, um mod feito para a versão 1.21.8, pode não funcionar na versão 1.21.11.</li><li>São para Fabric, não outro loader.</li><li>São para a edição correta do Minecraft (Java Edition).</li></ul><h2 id="2-move-the-mod-to-the-mods-folder" tabindex="-1">2. Mova o Mod para a pasta <code>mods</code> <a class="header-anchor" href="#2-move-the-mod-to-the-mods-folder" aria-label="Permalink to “2. Mova o Mod para a pasta mods”">​</a></h2><p>A pasta mods pode ser encontrada nos seguintes locais para cada sistema operacional.</p><p>Você pode colar esses caminhos na barra de endereços do seu explorador de arquivos para rapidamente achar a pasta.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language-text active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>Uma vez encontrada a pasta <code>mods</code>, você pode mover os arquivos <code>.jar</code> dos mods para dentro dela.</p><p><img src="/assets/players/installing-mods.png" alt="Installed mods in the mods folder" loading="lazy"></p><h2 id="3-you-re-done" tabindex="-1">3. Pronto! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. Pronto!”">​</a></h2><p>Uma vez que os mods foram movidos para a pasta <code>mods</code>, você pode abrir o Minecraft Launcher e selecionar o perfil do Fabric no menu suspenso no canto inferior esquerdo e clicar em jogar!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Minecraft Launcher with Fabric profile selected" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Solução de problemas <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Solução de problemas”">​</a></h2><p>Se encontrar algum problema enquanto segue o guia, você pode pedir ajuda no <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Discord do Fabric</a> no canal <code>#player-support</code>.</p><p>Você também pode tentar resolver o problema por conta própria lendo as páginas de solução de problemas:</p><ul><li><a href="./troubleshooting/crash-reports">Crash Reports</a></li><li><a href="./troubleshooting/uploading-logs">Uploading Logs</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};